 /// <summary>
 /// Specifies the unit of time for humanization purposes.
 /// Values are ordered from largest to smallest.
 /// </summary>
 public enum TimeUnit
 {
     /// <summary>Years.</summary>
     Year,
     /// <summary>Months.</summary>
     Month,
     /// <summary>Weeks.</summary>
     Week,
     /// <summary>Days.</summary>
