private static List<string?> CreateTimeParts(
    TimeSpan timeSpan, TimeUnit maxUnit, TimeUnit minUnit, CultureInfo culture)
{
    var timeParts = new List<string?>(8);
    var totalDays = Math.Abs(timeSpan.TotalDays);

    foreach (var unit in TimeUnits)
    {
        if (unit < minUnit || unit > maxUnit)
        {
            continue;
        }

        var value = unit switch
        {
            TimeUnit.Year => (int)(totalDays / DaysInAYear),
            TimeUnit.Month => (int)((totalDays % DaysInAYear) / DaysInAMonth),
            TimeUnit.Week => (int)((totalDays % DaysInAMonth) / DaysInAWeek),
            TimeUnit.Day => (int)(totalDays % DaysInAWeek),
            TimeUnit.Hour => timeSpan.Hours,
            TimeUnit.Minute => timeSpan.Minutes,
            TimeUnit.Second => timeSpan.Seconds,
            TimeUnit.Millisecond => timeSpan.Milliseconds,
            _ => 0
        };

        timeParts.Add(value != 0 ? FormatTimePart(value, unit) : null);
    }

    return timeParts;
}

private static bool IsContainingOnlyNullValue(List<string?> timeParts)
{
    for (var i = 0; i < timeParts.Count; i++)
    {
        if (timeParts[i] != null)
            return false;
    }
    return true;
}

/// <summary>
/// Filters and limits time parts to the requested precision, in-place.
/// </summary>
private static void SetPrecisionOfTimeSpan(
    List<string?> timeParts, int precision, bool countEmptyUnits)
{
    var kept = 0;
    var i = 0;
    while (i < timeParts.Count && kept < precision)
    {
        var isNonNull = timeParts[i] != null;
        if (countEmptyUnits || isNonNull)
            kept++;
        if (!isNonNull)
        {
            timeParts.RemoveAt(i);
            continue;
        }
        i++;
    }
    // Remove everything beyond the precision window
    if (i < timeParts.Count)
        timeParts.RemoveRange(i, timeParts.Count - i);
}

/// <summary>
/// Joins time part strings with the specified separator.
/// </summary>
private static string ConcatenateTimeSpanParts(
    List<string?> timeSpanParts, string collectionSeparator)
{
    // Count non-null parts and find positions without allocating a filtered list
    var nonNullCount = 0;
    var lastNonNullIndex = -1;
    for (var i = 0; i < timeSpanParts.Count; i++)
    {
        if (timeSpanParts[i] != null)
        {
            nonNullCount++;
            lastNonNullIndex = i;
        }
    }

